const statsItems = $('Fetch Ad Stats').first().json;
const adsItems = $('Fetch Active Ads').first().json;
const crmItems = $('Fetch CRM Leads').all().map(i => i.json);
const posItems = $('Fetch Positions').all().map(i => i.json);

const statsData = statsItems?.data?.result?.data || statsItems?.data || (Array.isArray(statsItems) ? statsItems : []);
const adsData = adsItems?.data?.result?.data || adsItems?.data || (Array.isArray(adsItems) ? adsItems : []);

if (!Array.isArray(statsData) || !Array.isArray(adsData)) {
  return [{ json: { error: 'Invalid data' } }];
}

// Build CRM leads map: ad_id -> { leads, deps, rev }
const crmMap = {};
crmItems.forEach(row => {
  const adId = Number(row.ad_id);
  if (adId) crmMap[adId] = { leads: row.total_leads || 0, deps: row.depositors || 0, rev: Number(row.crm_revenue) || 0 };
});

// Build position map: ad_id -> { avg_position, best_position }
const posMap = {};
posItems.forEach(row => {
  const adId = Number(row.ad_id);
  if (adId) posMap[adId] = { avg: Number(row.avg_position) || 99, best: Number(row.best_position) || 99 };
});

// Build ads map for current bids
const adsMap = {};
adsData.forEach(ad => {
  let currentBid = 0;
  if (ad.bids && Array.isArray(ad.bids)) {
    const findBid = (node) => {
      if (node.bid) return Number(node.bid);
      if (node.children) { for (const c of Object.values(node.children)) { const b = findBid(c); if (b > 0) return b; } }
      return 0;
    };
    for (const b of ad.bids) { const f = findBid(b); if (f > 0) { currentBid = f; break; } }
  }
  adsMap[ad.id] = { current_bid: currentBid, ad_group_id: ad.ad_group_id, status_id: ad.status_id };
});

const maxCeiling = 0.15;
const minSpendForDecision = 50;
const minSpendForStop = 100;
const minClicksForDecision = 500;
const actions = [];

statsData.forEach(d => {
  const adId = d.ad_id;
  const spend = d.money || 0;
  const clicks = d.clicks_count || 0;
  const shows = d.shows_count || 0;
  const ctr = shows > 0 ? (clicks / shows * 100) : 0;
  const currentBid = adsMap[adId]?.current_bid || 0;

  // CRM data = source of truth
  const crm = crmMap[adId] || { leads: 0, deps: 0, rev: 0 };
  const totalLeads = crm.leads;
  const depositors = crm.deps;
  const crmRevenue = crm.rev;
  const roi = spend > 0 ? ((crmRevenue - spend) / spend * 100) : 0;
  const cr = clicks > 0 ? (totalLeads / clicks * 100) : 0;
  const depRate = totalLeads > 0 ? (depositors / totalLeads * 100) : 0;

  // Position data
  const pos = posMap[adId] || { avg: 99, best: 99 };
  const avgPos = pos.avg;
  const isTopPosition = avgPos <= 2;
  const isGoodPosition = avgPos <= 5;

  let action = 'HOLD';
  let bidMultiplier = 1.0;
  let reason = '';

  // Rule 1: Golden teaser + NOT already top position = raise bid
  if (depositors > 0 && roi > 0 && ctr > 1.5 && clicks > 100 && !isTopPosition) {
    action = 'RAISE_BID';
    bidMultiplier = 1.15;
    reason = `Golden: ${depositors}D/${totalLeads}L, ROI ${roi.toFixed(0)}%, pos ${avgPos}, +15%`;
  }
  // Rule 1b: Golden teaser but already top = HOLD (no need to raise)
  else if (depositors > 0 && roi > 0 && ctr > 1.5 && clicks > 100 && isTopPosition) {
    action = 'HOLD';
    reason = `Golden but top pos ${avgPos}, no raise needed`;
  }
  // Rule 2: Profitable + not in good position = raise
  else if (depositors > 0 && roi > 30 && clicks > 200 && !isGoodPosition) {
    action = 'RAISE_BID';
    bidMultiplier = 1.10;
    reason = `Profitable: ${depositors}D, ROI ${roi.toFixed(0)}%, pos ${avgPos}, +10%`;
  }
  // Rule 2b: Profitable + already good position = hold
  else if (depositors > 0 && roi > 30 && clicks > 200 && isGoodPosition) {
    action = 'HOLD';
    reason = `Profitable at pos ${avgPos}, holding`;
  }
  // Rule 3: Has depositors, marginal ROI = hold
  else if (depositors > 0 && roi >= -20) {
    action = 'HOLD';
    reason = `Stable: ${depositors}D/${totalLeads}L, ROI ${roi.toFixed(0)}%, pos ${avgPos}`;
  }
  // Rule 4: Has leads, no deps yet, moderate spend = hold (wait for approval)
  else if (totalLeads > 0 && depositors === 0 && spend < minSpendForStop) {
    action = 'HOLD';
    reason = `Waiting: ${totalLeads}L, 0D, $${spend.toFixed(2)}`;
  }
  // Rule 5: Has depositors but negative ROI = lower
  else if (depositors > 0 && roi < -20 && clicks > minClicksForDecision) {
    action = 'LOWER_BID';
    bidMultiplier = 0.85;
    reason = `Low ROI: ${depositors}D, ROI ${roi.toFixed(0)}%, pos ${avgPos}, -15%`;
  }
  // Rule 6: Leads but no deps + high spend = lower
  else if (totalLeads > 0 && depositors === 0 && spend > minSpendForStop) {
    action = 'LOWER_BID';
    bidMultiplier = 0.85;
    reason = `${totalLeads}L/0D in 3d, $${spend.toFixed(2)}, -15%`;
  }
  // Rule 7: ZERO leads + high spend = STOP
  else if (totalLeads === 0 && spend > minSpendForStop && clicks > minClicksForDecision) {
    action = 'STOP';
    reason = `0L in 3d, $${spend.toFixed(2)}, ${clicks} clicks`;
  }
  // Rule 8: ZERO leads + moderate spend = lower
  else if (totalLeads === 0 && spend > minSpendForDecision && clicks > 300) {
    action = 'LOWER_BID';
    bidMultiplier = 0.85;
    reason = `0L, $${spend.toFixed(2)}, ${clicks} clicks, -15%`;
  }
  // Rule 9: Dead teaser
  else if (clicks < 10 && shows > 5000) {
    action = 'STOP';
    reason = `Dead: ${clicks} clicks / ${shows} shows in 3d`;
  }

  if (action !== 'HOLD') {
    let newBid = currentBid * bidMultiplier;
    if (newBid > maxCeiling) newBid = maxCeiling;
    if (newBid < 0.001) newBid = 0.001;

    actions.push({
      json: {
        ad_id: adId,
        action: action,
        current_bid: currentBid,
        new_bid: action === 'STOP' ? currentBid : Math.round(newBid * 10000) / 10000,
        roi: Math.round(roi * 100) / 100,
        leads: totalLeads,
        depositors: depositors,
        dep_rate: Math.round(depRate * 100) / 100,
        crm_revenue: crmRevenue,
        avg_position: avgPos,
        clicks: clicks,
        shows: shows,
        spend: spend,
        ctr: Math.round(ctr * 10000) / 10000,
        cr: Math.round(cr * 10000) / 10000,
        reason: reason
      }
    });
  }
});

if (actions.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No bid changes needed' } }];
}

return actions;

